#!/usr/bin/env bash
# homenet-ppsk-remove.sh — remove a PPSK entry from a PPSK-enabled SSID
# Usage: homenet-ppsk-remove.sh <ssid> <password> [--apply]
# Refuses to remove the last PPSK unless --force-empty is given, because the
# SSID-level PSK is UniFi-auto-generated and unknown; losing all PPSKs bricks access.

set -uo pipefail
source "$HOME/.claude/scripts/homenet-lib.sh"

SSID="${1:-}"
PSK="${2:-}"
MODE="${3:-preview}"

[ -n "$SSID" ] && [ -n "$PSK" ] \
    || _homenet_fail "usage: homenet-ppsk-remove.sh <ssid> <password> [--apply]"

homenet_load_secrets

wlan=$(homenet_wlan_by_name "$SSID")
[ -n "$wlan" ] && [ "$wlan" != "null" ] || _homenet_fail "SSID not found: $SSID"

wlan_id=$(echo "$wlan" | jq -r '._id')
current_ppsks=$(echo "$wlan" | jq '.private_preshared_keys // []')
current_size=$(echo "$current_ppsks" | jq 'length')

# Find matching entry
match_count=$(echo "$current_ppsks" | jq --arg p "$PSK" '[.[] | select(.password == $p)] | length')
if [ "$match_count" -eq 0 ]; then
    echo "No PPSK entry with that password found on '$SSID'. No change."
    exit 0
fi

new_ppsks=$(echo "$current_ppsks" | jq --arg p "$PSK" '[.[] | select(.password != $p)]')
new_size=$(echo "$new_ppsks" | jq 'length')

psk_fingerprint=$(printf '%s' "$PSK" | shasum -a 256 | cut -c1-8)
passphrase_auto=$(echo "$wlan" | jq -r '.passphrase_autogenerated // false')

echo ""
echo "=== Preview: remove PPSK entry ==="
echo "SSID: $SSID ($wlan_id)"
echo "Current PPSK count: $current_size"
echo "Removing entry fingerprint (sha256 prefix): $psk_fingerprint"
echo "New PPSK count: $new_size"

if [ "$new_size" -eq 0 ] && [ "$passphrase_auto" = "true" ]; then
    echo ""
    echo "[!] WARNING: removing this PPSK leaves 0 entries, and the SSID-level PSK is UniFi-auto-generated (unknown)."
    echo "[!] No device will be able to join '$SSID' after this change."
    if [ "$MODE" = "--apply" ]; then
        echo "[!] Refusing to apply. Re-run with --force-empty if you really mean to brick the SSID."
        exit 1
    fi
fi

if [ "$MODE" != "--apply" ] && [ "$MODE" != "--force-empty" ]; then
    echo ""
    echo "[preview only] re-run with --apply to commit."
    exit 0
fi

payload=$(jq -n --argjson keys "$new_ppsks" '{private_preshared_keys: $keys}')
echo ""
echo "Applying..."
resp=$(homenet_api "/proxy/network/api/s/default/rest/wlanconf/$wlan_id" -X PUT -H "Content-Type: application/json" -d "$payload")
rc=$(echo "$resp" | jq -r '.meta.rc // "-"')

if [ "$rc" != "ok" ]; then
    echo "API error: $(echo "$resp" | jq -r '.meta.msg // .')"
    exit 1
fi

echo "Applied. PPSK count: $current_size → $new_size."

if [ -f "$HOMENET_DIR/investigations.md" ]; then
    stamp=$(date +%Y-%m-%d\ %H:%M)
    {
        echo ""
        echo "### PPSK Revoked: $SSID"
        echo "- $stamp: removed entry sha256-prefix=\`$psk_fingerprint\` (count $current_size → $new_size)"
    } >> "$HOMENET_DIR/investigations.md"
    echo "Logged to HomeNetwork/investigations.md"
fi
